import { useQuery } from '@tanstack/react-query'
import type { TokenBalance } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useAccount } from 'wagmi'
import { useYoClient } from '../context'

export function useTokenBalance(
  token: Address | undefined,
  account?: Address,
  options?: { enabled?: boolean },
) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()
  const { address: connectedAddress } = useAccount()
  const userAddress = account ?? connectedAddress

  const { data, isLoading, isError, error, refetch } = useQuery<TokenBalance, Error>({
    queryKey: ['yo-token-balance', token, userAddress, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      if (!token || !userAddress) throw new Error('Missing parameters')
      return client.getTokenBalance(token, userAddress)
    },
    enabled: enabled && !!client && !!token && !!userAddress,
    staleTime: 15_000,
    refetchInterval: 30_000,
  })

  return { balance: data, isLoading, isError, error: error ?? null, refetch }
}
