import { createYoClient, isSupportedChain, type SupportedChainId, type YoClient } from '@yo-protocol/core'
import { useMemo } from 'react'
import type { PublicClient } from 'viem'

export interface UseCreateYoClientOptions {
  chainId: number
  partnerId?: number
  publicClients?: Partial<Record<SupportedChainId, PublicClient>>
}

export function useCreateYoClient(options: UseCreateYoClientOptions): YoClient | null {
  const { chainId, partnerId, publicClients } = options

  return useMemo(() => {
    if (!isSupportedChain(chainId)) return null
    return createYoClient({ chainId: chainId as SupportedChainId, partnerId, publicClients })
  }, [chainId, partnerId, publicClients])
}
