import { useQueryClient } from '@tanstack/react-query'
import type { MerklChainRewards } from '@yo-protocol/core'
import { useCallback, useEffect, useState } from 'react'
import type { Hash } from 'viem'
import { useAccount, useSendTransaction, useWaitForTransactionReceipt } from 'wagmi'
import { useYieldConfig, useYoClient } from '../context'

export interface UseClaimMerklRewardsOptions {
  onSubmitted?: (hash: Hash) => void
  onConfirmed?: (hash: Hash) => void
  onError?: (error: Error) => void
}

export function useClaimMerklRewards(options?: UseClaimMerklRewardsOptions) {
  const { onError: globalOnError } = useYieldConfig()
  const { onSubmitted, onConfirmed, onError } = options ?? {}
  const client = useYoClient()
  const { address: account } = useAccount()
  const queryClient = useQueryClient()
  const { sendTransactionAsync } = useSendTransaction()

  const [hash, setHash] = useState<Hash | undefined>()
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<Error | null>(null)

  const { isSuccess } = useWaitForTransactionReceipt({ hash, query: { enabled: !!hash } })

  useEffect(() => {
    if (isSuccess && hash) {
      queryClient.invalidateQueries({ queryKey: ['merkl-rewards', account] })
      onConfirmed?.(hash)
    }
  }, [isSuccess, hash, queryClient, account, onConfirmed])

  const claim = useCallback(
    async (chainRewards: MerklChainRewards): Promise<Hash> => {
      if (!client) throw new Error('Client not available')
      if (!account) throw new Error('Account not connected')

      setIsLoading(true)
      setError(null)

      try {
        const tx = client.prepareClaimMerklRewards(account, chainRewards)
        const txHash = await sendTransactionAsync({ to: tx.to, data: tx.data, value: tx.value })
        setHash(txHash)
        onSubmitted?.(txHash)
        return txHash
      } catch (err) {
        const e = err instanceof Error ? err : new Error('Claim failed')
        setError(e)
        onError?.(e)
        globalOnError?.(e)
        throw e
      } finally {
        setIsLoading(false)
      }
    },
    [client, account, sendTransactionAsync, onSubmitted, onError, globalOnError],
  )

  const reset = useCallback(() => {
    setHash(undefined)
    setError(null)
    setIsLoading(false)
  }, [])

  return { claim, isLoading, isError: !!error, error, isSuccess, hash, reset }
}
