import { useQuery } from '@tanstack/react-query'
import type { UserVaultPosition } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useAccount } from 'wagmi'
import { useYoClient } from '../context'

export function useUserPositions(account?: Address, options?: { enabled?: boolean }) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()
  const { address: connectedAddress } = useAccount()
  const userAddress = account ?? connectedAddress

  const { data, isLoading, isError, error, refetch } = useQuery<
    Array<{ vault: unknown; position: UserVaultPosition }>,
    Error
  >({
    queryKey: ['yo-user-positions', userAddress, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      if (!userAddress) throw new Error('Account not connected')
      return client.getUserPositionsAllChains(userAddress)
    },
    enabled: enabled && !!client && !!userAddress,
    staleTime: 30_000,
    refetchInterval: 60_000,
  })

  return { positions: data ?? [], isLoading, isError, error: error ?? null, refetch }
}
