import { useQuery } from '@tanstack/react-query'
import type { UserBalances } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useAccount } from 'wagmi'
import { useYoClient } from '../context'

export function useUserBalances(user?: Address, options?: { enabled?: boolean }) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()
  const { address: connectedAddress } = useAccount()
  const account = user ?? connectedAddress

  const { data, isLoading, isError, error, refetch } = useQuery<UserBalances, Error>({
    queryKey: ['yo-user-balances', account, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      if (!account) throw new Error('Account not connected')
      return client.getUserBalances(account)
    },
    enabled: enabled && !!client && !!account,
    staleTime: 60_000,
    refetchInterval: 60_000,
  })

  return { balances: data, isLoading, isError, error: error ?? null, refetch }
}
