import { useQuery } from '@tanstack/react-query'
import type { PriceMap } from '@yo-protocol/core'
import { useYoClient } from '../context'

export function usePrices(options?: { enabled?: boolean }) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()

  const { data, isLoading, isError, error, refetch } = useQuery<PriceMap, Error>({
    queryKey: ['yo-prices', client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      return client.getPrices()
    },
    enabled: enabled && !!client,
    staleTime: 60_000,
  })

  return { prices: data ?? {}, isLoading, isError, error: error ?? null, refetch }
}
