import { useQuery } from '@tanstack/react-query'
import type { SharePriceHistoryPoint, VaultId } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useYoClient } from '../context'
import { resolveVaultAddress } from '../utils/vault'

export function useSharePriceHistory(vault: Address | VaultId, options?: { enabled?: boolean }) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()
  const vaultAddress = resolveVaultAddress(vault)

  const { data, isLoading, isError, error, refetch } = useQuery<SharePriceHistoryPoint[], Error>({
    queryKey: ['yo-share-price-history', vaultAddress, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      return client.getSharePriceHistory(vaultAddress)
    },
    enabled: enabled && !!client,
    staleTime: 5 * 60_000,
  })

  return { history: data ?? [], isLoading, isError, error: error ?? null, refetch }
}
