import { useQuery } from '@tanstack/react-query'
import type { MerklChainRewards } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useAccount } from 'wagmi'
import { useYoClient } from '../context'

export function useMerklRewards(account?: Address, options?: { enabled?: boolean }) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()
  const { address: connectedAddress } = useAccount()
  const userAddress = account ?? connectedAddress

  const { data, isLoading, isError, error, refetch } = useQuery<MerklChainRewards | null, Error>({
    queryKey: ['merkl-rewards', userAddress, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      if (!userAddress) throw new Error('Account not available')
      return client.getClaimableRewards(userAddress)
    },
    enabled: enabled && !!client && !!userAddress,
    staleTime: 60_000,
    refetchInterval: 120_000,
  })

  const totalClaimable = data ? client?.getMerklTotalClaimable(data) ?? 0n : 0n
  const hasClaimable = data ? client?.hasMerklClaimableRewards(data) ?? false : false

  return {
    rewards: data ?? undefined,
    totalClaimable,
    hasClaimable,
    isLoading,
    isError,
    error: error ?? null,
    refetch,
  }
}
