import { useQueryClient } from '@tanstack/react-query'
import type { RedeemReceipt, VaultId } from '@yo-protocol/core'
import { useCallback, useEffect, useState } from 'react'
import type { Address, Hash } from 'viem'
import { useAccount, useSendTransaction, useWaitForTransactionReceipt } from 'wagmi'
import { useYieldConfig, useYoClient } from '../context'
import { resolveVaultAddress } from '../utils/vault'

export type RedeemStep = 'idle' | 'approving' | 'redeeming' | 'waiting' | 'success' | 'error'

export interface UseRedeemOptions {
  vault: Address | VaultId
  onSubmitted?: (hash: Hash) => void
  onConfirmed?: (hash: Hash) => void
  onError?: (error: Error) => void
}

export function useRedeem(options: UseRedeemOptions) {
  const { onError: globalOnError } = useYieldConfig()
  const { vault, onSubmitted, onConfirmed, onError } = options
  const client = useYoClient()
  const { address: account } = useAccount()
  const queryClient = useQueryClient()
  const vaultAddress = resolveVaultAddress(vault)
  const { sendTransactionAsync } = useSendTransaction()

  const [hash, setHash] = useState<Hash | undefined>()
  const [approveHash, setApproveHash] = useState<Hash | undefined>()
  const [step, setStep] = useState<RedeemStep>('idle')
  const [error, setError] = useState<Error | null>(null)
  const [receipt, setReceipt] = useState<RedeemReceipt | undefined>()

  const { isSuccess } = useWaitForTransactionReceipt({ hash, query: { enabled: !!hash } })

  useEffect(() => {
    if (!isSuccess || !hash || !client) return

    setStep('success')
    queryClient.invalidateQueries({ queryKey: ['yo-user-position', vaultAddress, account] })
    queryClient.invalidateQueries({ queryKey: ['yo-vault-state', vaultAddress] })
    queryClient.invalidateQueries({ queryKey: ['yo-share-balance'] })
    queryClient.invalidateQueries({ queryKey: ['yo-pending-redemptions'] })
    onConfirmed?.(hash)

    client.waitForRedeemReceipt(hash).then(setReceipt).catch(() => {})
  }, [isSuccess, hash, client, queryClient, vaultAddress, account, onConfirmed])

  const redeem = useCallback(
    async (shares: bigint): Promise<Hash> => {
      if (!client) throw new Error('Client not available')
      if (!account) throw new Error('Account not connected')

      setStep('idle')
      setError(null)

      try {
        setStep('approving')
        const txs = await client.prepareRedeemWithApproval({
          vault: vaultAddress,
          shares,
          owner: account,
          recipient: account,
        })

        if (txs.length > 1) {
          const approveTx = txs[0]!
          const appHash = await sendTransactionAsync({ to: approveTx.to, data: approveTx.data, value: approveTx.value })
          setApproveHash(appHash)
          await client.waitForTransaction(appHash)
        }

        setStep('redeeming')
        const redeemTx = txs[txs.length - 1]!
        const redeemHash = await sendTransactionAsync({ to: redeemTx.to, data: redeemTx.data, value: redeemTx.value })
        setHash(redeemHash)
        setStep('waiting')
        onSubmitted?.(redeemHash)
        return redeemHash
      } catch (err) {
        const e = err instanceof Error ? err : new Error('Redeem failed')
        setStep('error')
        setError(e)
        onError?.(e)
        globalOnError?.(e)
        throw e
      }
    },
    [client, account, vaultAddress, sendTransactionAsync, onSubmitted, onError, globalOnError],
  )

  const reset = useCallback(() => {
    setHash(undefined)
    setApproveHash(undefined)
    setError(null)
    setStep('idle')
    setReceipt(undefined)
  }, [])

  return {
    redeem,
    step,
    isLoading: step !== 'idle' && step !== 'success' && step !== 'error',
    isError: step === 'error',
    error,
    isSuccess,
    hash,
    approveHash,
    instant: receipt?.instant,
    assetsOrRequestId: receipt?.assetsOrRequestId,
    reset,
  }
}
