import { useQuery } from '@tanstack/react-query'
import type { TimeseriesPoint, VaultId } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useYoClient } from '../context'
import { resolveVaultAddress } from '../utils/vault'

export function useVaultHistory(vault: Address | VaultId, options?: { enabled?: boolean }) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()
  const vaultAddress = resolveVaultAddress(vault)

  const yieldQuery = useQuery<TimeseriesPoint[], Error>({
    queryKey: ['yo-vault-yield-history', vaultAddress, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      return client.getVaultYieldHistory(vaultAddress)
    },
    enabled: enabled && !!client,
    staleTime: 5 * 60_000,
  })

  const tvlQuery = useQuery<TimeseriesPoint[], Error>({
    queryKey: ['yo-vault-tvl-history', vaultAddress, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      return client.getVaultTvlHistory(vaultAddress)
    },
    enabled: enabled && !!client,
    staleTime: 5 * 60_000,
  })

  return {
    yieldHistory: yieldQuery.data ?? [],
    tvlHistory: tvlQuery.data ?? [],
    isLoading: yieldQuery.isLoading || tvlQuery.isLoading,
    isError: yieldQuery.isError || tvlQuery.isError,
    error: yieldQuery.error ?? tvlQuery.error ?? null,
    refetch: () => { yieldQuery.refetch(); tvlQuery.refetch() },
  }
}
