import { useQuery } from '@tanstack/react-query'
import type { TotalTvlTimeseriesPoint } from '@yo-protocol/core'
import { useYoClient } from '../context'

export function useTotalTvl(options?: { enabled?: boolean }) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()

  const { data, isLoading, isError, error, refetch } = useQuery<TotalTvlTimeseriesPoint[], Error>({
    queryKey: ['yo-total-tvl', client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      return client.getTotalTvlTimeseries()
    },
    enabled: enabled && !!client,
    staleTime: 5 * 60_000,
  })

  return { tvl: data ?? [], isLoading, isError, error: error ?? null, refetch }
}
