import { useQuery } from '@tanstack/react-query'
import type { GlobalVaultHistoryResponse, VaultActivityFilters } from '@yo-protocol/core'
import { useYoClient } from '../context'

export interface UseGlobalVaultHistoryOptions {
  cursor?: number
  limit?: number
  filters?: VaultActivityFilters
  enabled?: boolean
}

export function useGlobalVaultHistory(options?: UseGlobalVaultHistoryOptions) {
  const { cursor, limit, filters, enabled = true } = options ?? {}
  const client = useYoClient()

  const { data, isLoading, isError, error, refetch } = useQuery<GlobalVaultHistoryResponse, Error>({
    queryKey: ['yo-global-vault-history', cursor, limit, filters, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      return client.getGlobalVaultHistory({ cursor, limit, filters })
    },
    enabled: enabled && !!client,
    staleTime: 30_000,
  })

  return { history: data, isLoading, isError, error: error ?? null, refetch }
}
