import { useQuery } from '@tanstack/react-query'
import type { UserHistoryItem, VaultId } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useAccount } from 'wagmi'
import { useYoClient } from '../context'
import { resolveVaultAddress } from '../utils/vault'

export function useUserHistory(
  vault: Address | VaultId,
  user?: Address,
  options?: { limit?: number; enabled?: boolean },
) {
  const { limit, enabled = true } = options ?? {}
  const client = useYoClient()
  const { address: connectedAddress } = useAccount()
  const account = user ?? connectedAddress
  const vaultAddress = resolveVaultAddress(vault)

  const { data, isLoading, isError, error, refetch } = useQuery<UserHistoryItem[], Error>({
    queryKey: ['yo-user-history', vaultAddress, account, limit, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      if (!account) throw new Error('Account not available')
      return client.getUserHistory(vaultAddress, account, limit)
    },
    enabled: enabled && !!client && !!account,
    staleTime: 30_000,
  })

  return { history: data ?? [], isLoading, isError, error: error ?? null, refetch }
}
